40	/**
41	 * @brief A helper method to log statistics on the APNetlist.
42	 */
43	static void print_ap_netlist_stats(const APNetlist& netlist) {
44	    // Get the number of moveable and fixed blocks
45	    size_t num_moveable_blocks = 0;
46	    size_t num_fixed_blocks = 0;
47	    for (APBlockId blk_id : netlist.blocks()) {
48	        if (netlist.block_mobility(blk_id) == APBlockMobility::MOVEABLE)
49	            num_moveable_blocks++;
50	        else
51	            num_fixed_blocks++;
52	    }
53	    // Get the fanout information of nets
54	    size_t highest_fanout = 0;
55	    float average_fanout = 0.f;
56	    unsigned net_count = 0;
57	    for (APNetId net_id : netlist.nets()) {
58	        if (netlist.net_is_ignored(net_id))
59	            continue;
60	        size_t net_fanout = netlist.net_pins(net_id).size();
61	        if (net_fanout > highest_fanout)
62	            highest_fanout = net_fanout;
63	        average_fanout += static_cast<float>(net_fanout);
64	        net_count++;
65	    }
66	    average_fanout /= static_cast<float>(net_count);
67	    // Print the statistics
68	    VTR_LOG("Analytical Placement Netlist Statistics:\n");
69	    VTR_LOG("\tAP Blocks: %zu\n", netlist.blocks().size());
70	    VTR_LOG("\t\tMoveable AP Blocks: %zu\n", num_moveable_blocks);
71	    VTR_LOG("\t\tFixed AP Blocks: %zu\n", num_fixed_blocks);
72	    VTR_LOG("\tAP Nets: %zu\n", net_count);
73	    VTR_LOG("\t\tAverage Fanout: %.2f\n", average_fanout);
74	    VTR_LOG("\t\tHighest Fanout: %zu\n", highest_fanout);
75	    VTR_LOG("\tAP Pins: %zu\n", netlist.pins().size());
76	    VTR_LOG("\n");
77	}
78	
79	/**
80	 * @brief Passes the flat placement information to a provided partial placement.
81	 *
82	 *  @param flat_placement_info    The flat placement information to be read.
83	 *  @param ap_netlist             The APNetlist that used to iterate over its blocks.
84	 *  @param prepacker              The Prepacker to get molecule of blocks in the ap_netlist.
85	 *  @param p_placement            The partial placement to be updated which is assumed
86	 * to be generated on ap_netlist or have the same blocks.
87	 */
88	static void convert_flat_to_partial_placement(const FlatPlacementInfo& flat_placement_info, const APNetlist& ap_netlist, const Prepacker& prepacker, PartialPlacement& p_placement) {
89	    size_t num_mols_assigned_to_center = 0;
90	    for (APBlockId ap_blk_id : ap_netlist.blocks()) {
91	        // Get location of a valid atom across all molecules in this AP block
92	        // and verify that all atoms in the block share the same placement info.
93	        float atom_loc_x = 0.f, atom_loc_y = 0.f, atom_loc_layer = 0.f;
94	        int atom_loc_sub_tile = 0;
95	        bool found_valid_atom = false;
96	        for (PackMoleculeId mol_id : ap_netlist.block_molecules(ap_blk_id)) {
97	            const t_pack_molecule& mol = prepacker.get_molecule(mol_id);
98	            for (AtomBlockId atom_blk_id : mol.atom_block_ids) {
99	                if (!atom_blk_id.is_valid())
100	                    continue;
101	                float current_loc_x = flat_placement_info.blk_x_pos[atom_blk_id];
102	                float current_loc_y = flat_placement_info.blk_y_pos[atom_blk_id];
103	                float current_loc_layer = flat_placement_info.blk_layer[atom_blk_id];
104	                int current_loc_sub_tile = flat_placement_info.blk_sub_tile[atom_blk_id];
105	                if (found_valid_atom) {
106	                    if (current_loc_x == -1 || current_loc_y == -1)
107	                        continue;
108	                    if (current_loc_x != atom_loc_x || current_loc_y != atom_loc_y || current_loc_layer != atom_loc_layer || current_loc_sub_tile != atom_loc_sub_tile)
109	                        VPR_FATAL_ERROR(VPR_ERROR_AP,
110	                                        "AP block %s contains atom %s (ID: %zu) with a location (%g, %g, layer: %g, subtile: %d) "
111	                                        "that conflicts the location of other atoms in this block of (%g, %g, layer: %g, subtile: %d).",
112	                                        ap_netlist.block_name(ap_blk_id).c_str(),
113	                                        g_vpr_ctx.atom().netlist().block_name(atom_blk_id).c_str(), atom_blk_id,
114	                                        current_loc_x, current_loc_y, current_loc_layer, current_loc_sub_tile,
115	                                        atom_loc_x, atom_loc_y, atom_loc_layer, atom_loc_sub_tile);
116	                } else {
117	                    if (current_loc_x != -1 && current_loc_y != -1) {
118	                        atom_loc_x = std::clamp(current_loc_x, 0.0f,
119	                                                static_cast<float>(g_vpr_ctx.device().grid.width() - 1));
120	                        atom_loc_y = std::clamp(current_loc_y, 0.0f,
121	                                                static_cast<float>(g_vpr_ctx.device().grid.height() - 1));
122	                        // If current_loc_layer or current_loc_sub_tile are unset (-1), default to layer 0 and sub_tile 0.
123	                        if (current_loc_layer == -1)
124	                            current_loc_layer = 0;
125	                        if (current_loc_sub_tile == -1)
126	                            current_loc_sub_tile = 0;
127	                        atom_loc_layer = current_loc_layer;
128	                        atom_loc_sub_tile = current_loc_sub_tile;
129	                        found_valid_atom = true;
130	                    }
131	                }
132	            }
133	        }
134	        // If any atom in the block has a location assigned, use that location
135	        // for the entire AP block. Otherwise, assign the AP block to the center
136	        // of the device grid and update the flat placement info for all its atoms accordingly.
137	        if (!found_valid_atom) {
138	            num_mols_assigned_to_center++;
139	            VTR_LOG_WARN("No atoms of AP block %s provided in the flat placement. Assigning it to the device center.\n",
140	                         ap_netlist.block_name(ap_blk_id).c_str());
141	            p_placement.block_x_locs[ap_blk_id] = g_vpr_ctx.device().grid.width() / 2.0f;
142	            p_placement.block_y_locs[ap_blk_id] = g_vpr_ctx.device().grid.height() / 2.0f;
143	            p_placement.block_layer_nums[ap_blk_id] = 0;
144	            p_placement.block_sub_tiles[ap_blk_id] = 0;
145	            // Update flat placement for all atoms in all molecules of the block.
146	            // Needed for flat placement reconstruction statistics reporting.
147	            for (PackMoleculeId mol_id : ap_netlist.block_molecules(ap_blk_id)) {
148	                const t_pack_molecule& mol = prepacker.get_molecule(mol_id);
149	                for (AtomBlockId atom_blk_id : mol.atom_block_ids) {
150	                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_x_pos[atom_blk_id] = g_vpr_ctx.device().grid.width() / 2.0f;
151	                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_y_pos[atom_blk_id] = g_vpr_ctx.device().grid.height() / 2.0f;
152	                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_layer[atom_blk_id] = 0;
153	                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_sub_tile[atom_blk_id] = 0;
154	                }
155	            }
156	        } else {
157	            // Pass the placement information
158	            p_placement.block_x_locs[ap_blk_id] = atom_loc_x;
159	            p_placement.block_y_locs[ap_blk_id] = atom_loc_y;
160	            p_placement.block_layer_nums[ap_blk_id] = atom_loc_layer;
161	            p_placement.block_sub_tiles[ap_blk_id] = atom_loc_sub_tile;
162	        }
163	        // For fixed blocks, constraint positions take priority over flat placement.
164	        // Flat placement files use anchor positions; std::floor converts AP coordinates
165	        // (tile center) back to anchor positions.
166	        if (ap_netlist.block_mobility(ap_blk_id) == APBlockMobility::FIXED) {
167	            const APFixedBlockLoc& fixed_loc = ap_netlist.block_loc(ap_blk_id);
168	            if (fixed_loc.x != -1)
169	                p_placement.block_x_locs[ap_blk_id] = std::floor(fixed_loc.x);
170	            if (fixed_loc.y != -1)
171	                p_placement.block_y_locs[ap_blk_id] = std::floor(fixed_loc.y);
172	            if (fixed_loc.layer_num != -1)
173	                p_placement.block_layer_nums[ap_blk_id] = fixed_loc.layer_num;
174	            if (fixed_loc.sub_tile != -1)
175	                p_placement.block_sub_tiles[ap_blk_id] = fixed_loc.sub_tile;
176	        }
177	    }
178	    VTR_LOG("%zu of %zu molecules placed at device center (no atoms of these molecules found in flat placement).\n",
179	            num_mols_assigned_to_center, ap_netlist.blocks().size());
180	}
181	
182	/**
183	 * @brief If a flat placement is provided, skips the Global Placer and
184	 * converts it to a partial placement. Otherwise, runs the Global Placer.
185	 */
186	static PartialPlacement run_global_placer(const t_ap_opts& ap_opts,
187	                                          const AtomNetlist& atom_nlist,
188	                                          const APNetlist& ap_netlist,
189	                                          const Prepacker& prepacker,
190	                                          PreClusterTimingManager& pre_cluster_timing_manager,
191	                                          std::shared_ptr<PlaceDelayModel> place_delay_model,
192	                                          const DeviceContext& device_ctx) {
193	    if (g_vpr_ctx.atom().flat_placement_info().valid) {
194	        VTR_LOG("Flat Placement is provided in the AP flow, skipping the Global Placement.\n");
195	        PartialPlacement p_placement(ap_netlist);
196	        convert_flat_to_partial_placement(g_vpr_ctx.atom().flat_placement_info(),
197	                                          ap_netlist,
198	                                          prepacker,
199	                                          p_placement);
200	        return p_placement;
201	    } else {
202	        // Run the Global Placer
203	        std::unique_ptr<GlobalPlacer> global_placer = make_global_placer(ap_opts.analytical_solver_type,
204	                                                                         ap_opts.partial_legalizer_type,
205	                                                                         ap_netlist,
206	                                                                         prepacker,
207	                                                                         atom_nlist,
208	                                                                         device_ctx.grid,
209	                                                                         device_ctx.logical_block_types,
210	                                                                         device_ctx.physical_tile_types,
211	                                                                         device_ctx.arch->models,
212	                                                                         pre_cluster_timing_manager,
213	                                                                         place_delay_model,
214	                                                                         ap_opts.ap_timing_tradeoff,
215	                                                                         ap_opts.generate_mass_report,
216	                                                                         ap_opts.ap_partial_legalizer_target_density,
217	                                                                         ap_opts.num_threads,
218	                                                                         ap_opts.log_verbosity);
219	        return global_placer->place();
220	    }
221	}
222	
223	void run_analytical_placement_flow(t_vpr_setup& vpr_setup) {
224	    // Start an overall timer for the Analytical Placement flow.
225	    vtr::ScopedStartFinishTimer timer("Analytical Placement");
226	
227	    // The global state used/modified by this flow.
228	    const AtomNetlist& atom_nlist = g_vpr_ctx.atom().netlist();
229	    const DeviceContext& device_ctx = g_vpr_ctx.device();
230	    const UserPlaceConstraints& constraints = g_vpr_ctx.floorplanning().constraints;
231	    const t_ap_opts& ap_opts = vpr_setup.APOpts;
232	
233	    // Run the prepacker
234	    const Prepacker prepacker(atom_nlist, device_ctx.arch->models, device_ctx.logical_block_types);
235	
236	    // Pre-compute the pre-clustering timing delays. This object will be passed
237	    // into the global placer and the full legalizer to make them timing driven.
238	    PreClusterTimingManager pre_cluster_timing_manager(vpr_setup.PackerOpts.timing_driven,
239	                                                       atom_nlist,
240	                                                       g_vpr_ctx.atom().lookup(),
241	                                                       prepacker,
242	                                                       vpr_setup.PackerOpts.timing_update_type,
243	                                                       *device_ctx.arch,
244	                                                       vpr_setup.RoutingArch,
245	                                                       vpr_setup.PackerOpts.device_layout,
246	                                                       vpr_setup.AnalysisOpts);
247	
248	    // Estimate the device size before packing and build the RR graph if necessary.
249	    // When auto-sizing is used, this sets the device grid to the estimated size so
250	    // that downstream stages (e.g. RAM mapper, global placement) can query realistic
251	    // device dimensions before packing. The packer may later grow or shrink the device
252	    // size to match the actual resource requirements after packing completes.
253	    DeviceSizeEstimator device_size_estimator(vpr_setup, *device_ctx.arch, prepacker);
254	
255	    // Infer logical RAMs and assign to physical types to prioritize during packing.
256	    // For the auto-device flow, reuse the groups already computed by the estimator.
257	    RamMapper ram_mapper;
258	    if (vpr_setup.PackerOpts.use_ram_mapper) {
259	        ram_mapper = RamMapper(g_vpr_ctx.atom().netlist(),
260	                               prepacker,
261	                               pre_cluster_timing_manager,
262	                               device_size_estimator.ram_groups(),
263	                               ap_opts.log_verbosity,
264	                               /*is_fixed_device=*/has_fixed_device_size(vpr_setup));
265	    }
266	
267	    // Create the ap netlist from the atom netlist using the result from the
268	    // prepacker and ram mapper.
269	    APNetlist ap_netlist = gen_ap_netlist_from_atoms(atom_nlist,
270	                                                     prepacker,
271	                                                     ram_mapper,
272	                                                     constraints,
273	                                                     ap_opts.ap_high_fanout_threshold);
274	    print_ap_netlist_stats(ap_netlist);
275	
276	    // Pre-compute the place delay model. This will be passed into the global
277	    // placer to create a more accurate timing model.
278	    std::shared_ptr<PlaceDelayModel> place_delay_model;
279	    if (pre_cluster_timing_manager.is_valid()) {
280	        place_delay_model = PlacementDelayModelCreator::create_delay_model(vpr_setup.PlacerOpts,
281	                                                                           vpr_setup.RouterOpts,
282	                                                                           vpr_setup.CRROpts,
283	                                                                           (const Netlist<>&)atom_nlist,
284	                                                                           vpr_setup.RoutingArch,
285	                                                                           vpr_setup.Segments,
286	                                                                           device_ctx.arch->Chans,
287	                                                                           device_ctx.arch->directs,
288	                                                                           false /*is_flat*/);
289	    }
290	
291	    // Initialize graphics here, after the device grid exists, so the draw structures
292	    // can be allocated.
293	    init_ap_graphics(vpr_setup, *device_ctx.arch);
294	
295	    // Run the Global Placer.
296	    PartialPlacement p_placement = run_global_placer(ap_opts,
297	                                                     atom_nlist,
298	                                                     ap_netlist,
299	                                                     prepacker,
300	                                                     pre_cluster_timing_manager,
301	                                                     place_delay_model,
302	                                                     device_ctx);
303	
304	    // Verify that the partial placement is valid before running the full
305	    // legalizer.
306	    const size_t device_width = device_ctx.grid.width();
307	    const size_t device_height = device_ctx.grid.height();
308	    VTR_ASSERT(p_placement.verify(ap_netlist,
309	                                  device_width,
310	                                  device_height,
311	                                  device_ctx.grid.get_num_layers()));
312	
313	    // Generate the pre-cluster timing report now that global placement has
314	    // updated the timing arc delays to reflect the flat placement.
315	    pre_cluster_timing_manager.generate_setup_timing_report(atom_nlist,
316	                                                            g_vpr_ctx.atom().lookup(),
317	                                                            *device_ctx.arch,
318	                                                            vpr_setup.AnalysisOpts);
319	
320	    // Run the Full Legalizer.
321	    std::unique_ptr<FullLegalizer> full_legalizer = make_full_legalizer(ap_opts.full_legalizer_type,
322	                                                                        ap_netlist,
323	                                                                        atom_nlist,
324	                                                                        prepacker,
325	                                                                        pre_cluster_timing_manager,
326	                                                                        ram_mapper,
327	                                                                        vpr_setup,
328	                                                                        *device_ctx.arch,
329	                                                                        device_ctx.grid);
330	    full_legalizer->legalize(p_placement);
331	
332	    // Print the number of resources in netlist and number of resources available in architecture
333	    float target_device_utilization = vpr_setup.PackerOpts.target_device_utilization;
334	    print_resource_usage();
335	    // Print the device utilization
336	    print_device_utilization(target_device_utilization);
337	
338	    // Write out a flat placement file at the end of Full Legalization if the
339	    // option is specified.
340	    if (!vpr_setup.FileNameOpts.write_legalized_flat_place_file.empty()) {
341	        write_flat_placement(vpr_setup.FileNameOpts.write_legalized_flat_place_file.c_str(),
342	                             g_vpr_ctx.clustering().clb_nlist,
343	                             g_vpr_ctx.placement().block_locs(),
344	                             g_vpr_ctx.clustering().atoms_lookup);
345	    }
346	
347	    // Run the Detailed Placer.
348	    std::unique_ptr<DetailedPlacer> detailed_placer = make_detailed_placer(ap_opts.detailed_placer_type,
349	                                                                           g_vpr_ctx.placement().blk_loc_registry(),
350	                                                                           atom_nlist,
351	                                                                           g_vpr_ctx.clustering().clb_nlist,
352	                                                                           vpr_setup,
353	                                                                           *device_ctx.arch);
354	    detailed_placer->optimize_placement();
355	
356	    // Clean up some of the global variables that will no longer be used outside
357	    // of this flow.
358	    g_vpr_ctx.mutable_placement().clean_placement_context_post_place();
359	    g_vpr_ctx.mutable_floorplanning().clean_floorplanning_context_post_place();
360	}
