/**
 * @file
 * @author  Alex Singer
 * @date    September 2024
 * @brief   Implementation of the Analytical Placement flow.
 */

#include "analytical_placement_flow.h"
#include <memory>
#include "PlacementDelayModelCreator.h"
#include "PreClusterTimingManager.h"
#include "analytical_solver.h"
#include "ap_draw_manager.h"
#include "ap_netlist.h"
#include "atom_netlist.h"
#include "cluster_util.h"
#include "detailed_placer.h"
#include "device_size_estimate.h"
#include "full_legalizer.h"
#include "setup_grid.h"
#include "logical_ram_infer.h"
#include "gen_ap_netlist_from_atoms.h"
#include "global_placer.h"
#include "globals.h"
#include "load_flat_place.h"
#include "netlist_fwd.h"
#include "partial_legalizer.h"
#include "partial_placement.h"
#include "physical_types.h"
#include "place_delay_model.h"
#include "prepack.h"
#include "user_place_constraints.h"
#include "vpr_context.h"
#include "vpr_types.h"
#include "stats.h"
#include "vtr_assert.h"
#include "vtr_time.h"
#include "vtr_math.h"

/**
 * @brief A helper method to log statistics on the APNetlist.
 */
static void print_ap_netlist_stats(const APNetlist& netlist) {
    // Get the number of moveable and fixed blocks
    size_t num_moveable_blocks = 0;
    size_t num_fixed_blocks = 0;
    for (APBlockId blk_id : netlist.blocks()) {
        if (netlist.block_mobility(blk_id) == APBlockMobility::MOVEABLE)
            num_moveable_blocks++;
        else
            num_fixed_blocks++;
    }
    // Get the fanout information of nets
    size_t highest_fanout = 0;
    float average_fanout = 0.f;
    unsigned net_count = 0;
    for (APNetId net_id : netlist.nets()) {
        if (netlist.net_is_ignored(net_id))
            continue;
        size_t net_fanout = netlist.net_pins(net_id).size();
        if (net_fanout > highest_fanout)
            highest_fanout = net_fanout;
        average_fanout += static_cast<float>(net_fanout);
        net_count++;
    }
    average_fanout /= static_cast<float>(net_count);
    // Print the statistics
    VTR_LOG("Analytical Placement Netlist Statistics:\n");
    VTR_LOG("\tAP Blocks: %zu\n", netlist.blocks().size());
    VTR_LOG("\t\tMoveable AP Blocks: %zu\n", num_moveable_blocks);
    VTR_LOG("\t\tFixed AP Blocks: %zu\n", num_fixed_blocks);
    VTR_LOG("\tAP Nets: %zu\n", net_count);
    VTR_LOG("\t\tAverage Fanout: %.2f\n", average_fanout);
    VTR_LOG("\t\tHighest Fanout: %zu\n", highest_fanout);
    VTR_LOG("\tAP Pins: %zu\n", netlist.pins().size());
    VTR_LOG("\n");
}

/**
 * @brief Passes the flat placement information to a provided partial placement.
 *
 *  @param flat_placement_info    The flat placement information to be read.
 *  @param ap_netlist             The APNetlist that used to iterate over its blocks.
 *  @param prepacker              The Prepacker to get molecule of blocks in the ap_netlist.
 *  @param p_placement            The partial placement to be updated which is assumed
 * to be generated on ap_netlist or have the same blocks.
 */
static void convert_flat_to_partial_placement(const FlatPlacementInfo& flat_placement_info, const APNetlist& ap_netlist, const Prepacker& prepacker, PartialPlacement& p_placement) {
    size_t num_mols_assigned_to_center = 0;
    for (APBlockId ap_blk_id : ap_netlist.blocks()) {
        // Get location of a valid atom across all molecules in this AP block
        // and verify that all atoms in the block share the same placement info.
        float atom_loc_x = 0.f, atom_loc_y = 0.f, atom_loc_layer = 0.f;
        int atom_loc_sub_tile = 0;
        bool found_valid_atom = false;
        for (PackMoleculeId mol_id : ap_netlist.block_molecules(ap_blk_id)) {
            const t_pack_molecule& mol = prepacker.get_molecule(mol_id);
            for (AtomBlockId atom_blk_id : mol.atom_block_ids) {
                if (!atom_blk_id.is_valid())
                    continue;
                float current_loc_x = flat_placement_info.blk_x_pos[atom_blk_id];
                float current_loc_y = flat_placement_info.blk_y_pos[atom_blk_id];
                float current_loc_layer = flat_placement_info.blk_layer[atom_blk_id];
                int current_loc_sub_tile = flat_placement_info.blk_sub_tile[atom_blk_id];
                if (found_valid_atom) {
                    if (current_loc_x == -1 || current_loc_y == -1)
                        continue;
                    if (current_loc_x != atom_loc_x || current_loc_y != atom_loc_y || current_loc_layer != atom_loc_layer || current_loc_sub_tile != atom_loc_sub_tile)
                        VPR_FATAL_ERROR(VPR_ERROR_AP,
                                        "AP block %s contains atom %s (ID: %zu) with a location (%g, %g, layer: %g, subtile: %d) "
                                        "that conflicts the location of other atoms in this block of (%g, %g, layer: %g, subtile: %d).",
                                        ap_netlist.block_name(ap_blk_id).c_str(),
                                        g_vpr_ctx.atom().netlist().block_name(atom_blk_id).c_str(), atom_blk_id,
                                        current_loc_x, current_loc_y, current_loc_layer, current_loc_sub_tile,
                                        atom_loc_x, atom_loc_y, atom_loc_layer, atom_loc_sub_tile);
                } else {
                    if (current_loc_x != -1 && current_loc_y != -1) {
                        atom_loc_x = std::clamp(current_loc_x, 0.0f,
                                                static_cast<float>(g_vpr_ctx.device().grid.width() - 1));
                        atom_loc_y = std::clamp(current_loc_y, 0.0f,
                                                static_cast<float>(g_vpr_ctx.device().grid.height() - 1));
                        // If current_loc_layer or current_loc_sub_tile are unset (-1), default to layer 0 and sub_tile 0.
                        if (current_loc_layer == -1)
                            current_loc_layer = 0;
                        if (current_loc_sub_tile == -1)
                            current_loc_sub_tile = 0;
                        atom_loc_layer = current_loc_layer;
                        atom_loc_sub_tile = current_loc_sub_tile;
                        found_valid_atom = true;
                    }
                }
            }
        }
        // If any atom in the block has a location assigned, use that location
        // for the entire AP block. Otherwise, assign the AP block to the center
        // of the device grid and update the flat placement info for all its atoms accordingly.
        if (!found_valid_atom) {
            num_mols_assigned_to_center++;
            VTR_LOG_WARN("No atoms of AP block %s provided in the flat placement. Assigning it to the device center.\n",
                         ap_netlist.block_name(ap_blk_id).c_str());
            p_placement.block_x_locs[ap_blk_id] = g_vpr_ctx.device().grid.width() / 2.0f;
            p_placement.block_y_locs[ap_blk_id] = g_vpr_ctx.device().grid.height() / 2.0f;
            p_placement.block_layer_nums[ap_blk_id] = 0;
            p_placement.block_sub_tiles[ap_blk_id] = 0;
            // Update flat placement for all atoms in all molecules of the block.
            // Needed for flat placement reconstruction statistics reporting.
            for (PackMoleculeId mol_id : ap_netlist.block_molecules(ap_blk_id)) {
                const t_pack_molecule& mol = prepacker.get_molecule(mol_id);
                for (AtomBlockId atom_blk_id : mol.atom_block_ids) {
                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_x_pos[atom_blk_id] = g_vpr_ctx.device().grid.width() / 2.0f;
                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_y_pos[atom_blk_id] = g_vpr_ctx.device().grid.height() / 2.0f;
                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_layer[atom_blk_id] = 0;
                    g_vpr_ctx.mutable_atom().mutable_flat_placement_info().blk_sub_tile[atom_blk_id] = 0;
                }
            }
        } else {
            // Pass the placement information
            p_placement.block_x_locs[ap_blk_id] = atom_loc_x;
            p_placement.block_y_locs[ap_blk_id] = atom_loc_y;
            p_placement.block_layer_nums[ap_blk_id] = atom_loc_layer;
            p_placement.block_sub_tiles[ap_blk_id] = atom_loc_sub_tile;
        }
        // For fixed blocks, constraint positions take priority over flat placement.
        // Flat placement files use anchor positions; std::floor converts AP coordinates
        // (tile center) back to anchor positions.
        if (ap_netlist.block_mobility(ap_blk_id) == APBlockMobility::FIXED) {
            const APFixedBlockLoc& fixed_loc = ap_netlist.block_loc(ap_blk_id);
            if (fixed_loc.x != -1)
                p_placement.block_x_locs[ap_blk_id] = std::floor(fixed_loc.x);
            if (fixed_loc.y != -1)
                p_placement.block_y_locs[ap_blk_id] = std::floor(fixed_loc.y);
            if (fixed_loc.layer_num != -1)
                p_placement.block_layer_nums[ap_blk_id] = fixed_loc.layer_num;
            if (fixed_loc.sub_tile != -1)
                p_placement.block_sub_tiles[ap_blk_id] = fixed_loc.sub_tile;
        }
    }
    VTR_LOG("%zu of %zu molecules placed at device center (no atoms of these molecules found in flat placement).\n",
            num_mols_assigned_to_center, ap_netlist.blocks().size());
}

/**
 * @brief If a flat placement is provided, skips the Global Placer and
 * converts it to a partial placement. Otherwise, runs the Global Placer.
 */
static PartialPlacement run_global_placer(const t_ap_opts& ap_opts,
                                          const AtomNetlist& atom_nlist,
                                          const APNetlist& ap_netlist,
                                          const Prepacker& prepacker,
                                          PreClusterTimingManager& pre_cluster_timing_manager,
                                          std::shared_ptr<PlaceDelayModel> place_delay_model,
                                          const DeviceContext& device_ctx) {
    if (g_vpr_ctx.atom().flat_placement_info().valid) {
        VTR_LOG("Flat Placement is provided in the AP flow, skipping the Global Placement.\n");
        PartialPlacement p_placement(ap_netlist);
        convert_flat_to_partial_placement(g_vpr_ctx.atom().flat_placement_info(),
                                          ap_netlist,
                                          prepacker,
                                          p_placement);
        return p_placement;
    } else {
        // Run the Global Placer
        std::unique_ptr<GlobalPlacer> global_placer = make_global_placer(ap_opts.analytical_solver_type,
                                                                         ap_opts.partial_legalizer_type,
                                                                         ap_netlist,
                                                                         prepacker,
                                                                         atom_nlist,
                                                                         device_ctx.grid,
                                                                         device_ctx.logical_block_types,
                                                                         device_ctx.physical_tile_types,
                                                                         device_ctx.arch->models,
                                                                         pre_cluster_timing_manager,
                                                                         place_delay_model,
                                                                         ap_opts.ap_timing_tradeoff,
                                                                         ap_opts.generate_mass_report,
                                                                         ap_opts.ap_partial_legalizer_target_density,
                                                                         ap_opts.num_threads,
                                                                         ap_opts.log_verbosity);
        return global_placer->place();
    }
}

void run_analytical_placement_flow(t_vpr_setup& vpr_setup) {
    // Start an overall timer for the Analytical Placement flow.
    vtr::ScopedStartFinishTimer timer("Analytical Placement");

    // The global state used/modified by this flow.
    const AtomNetlist& atom_nlist = g_vpr_ctx.atom().netlist();
    const DeviceContext& device_ctx = g_vpr_ctx.device();
    const UserPlaceConstraints& constraints = g_vpr_ctx.floorplanning().constraints;
    const t_ap_opts& ap_opts = vpr_setup.APOpts;

    // Run the prepacker
    const Prepacker prepacker(atom_nlist, device_ctx.arch->models, device_ctx.logical_block_types);

    // Pre-compute the pre-clustering timing delays. This object will be passed
    // into the global placer and the full legalizer to make them timing driven.
    PreClusterTimingManager pre_cluster_timing_manager(vpr_setup.PackerOpts.timing_driven,
                                                       atom_nlist,
                                                       g_vpr_ctx.atom().lookup(),
                                                       prepacker,
                                                       vpr_setup.PackerOpts.timing_update_type,
                                                       *device_ctx.arch,
                                                       vpr_setup.RoutingArch,
                                                       vpr_setup.PackerOpts.device_layout,
                                                       vpr_setup.AnalysisOpts);

    // Estimate the device size before packing and build the RR graph if necessary.
    // When auto-sizing is used, this sets the device grid to the estimated size so
    // that downstream stages (e.g. RAM mapper, global placement) can query realistic
    // device dimensions before packing. The packer may later grow or shrink the device
    // size to match the actual resource requirements after packing completes.
    DeviceSizeEstimator device_size_estimator(vpr_setup, *device_ctx.arch, prepacker);

    // Infer logical RAMs and assign to physical types to prioritize during packing.
    // For the auto-device flow, reuse the groups already computed by the estimator.
    RamMapper ram_mapper;
    if (vpr_setup.PackerOpts.use_ram_mapper) {
        ram_mapper = RamMapper(g_vpr_ctx.atom().netlist(),
                               prepacker,
                               pre_cluster_timing_manager,
                               device_size_estimator.ram_groups(),
                               ap_opts.log_verbosity,
                               /*is_fixed_device=*/has_fixed_device_size(vpr_setup));
    }

    // Create the ap netlist from the atom netlist using the result from the
    // prepacker and ram mapper.
    APNetlist ap_netlist = gen_ap_netlist_from_atoms(atom_nlist,
                                                     prepacker,
                                                     ram_mapper,
                                                     constraints,
                                                     ap_opts.ap_high_fanout_threshold);
    print_ap_netlist_stats(ap_netlist);

    // Pre-compute the place delay model. This will be passed into the global
    // placer to create a more accurate timing model.
    std::shared_ptr<PlaceDelayModel> place_delay_model;
    if (pre_cluster_timing_manager.is_valid()) {
        place_delay_model = PlacementDelayModelCreator::create_delay_model(vpr_setup.PlacerOpts,
                                                                           vpr_setup.RouterOpts,
                                                                           vpr_setup.CRROpts,
                                                                           (const Netlist<>&)atom_nlist,
                                                                           vpr_setup.RoutingArch,
                                                                           vpr_setup.Segments,
                                                                           device_ctx.arch->Chans,
                                                                           device_ctx.arch->directs,
                                                                           false /*is_flat*/);
    }

    // Initialize graphics here, after the device grid exists, so the draw structures
    // can be allocated.
    init_ap_graphics(vpr_setup, *device_ctx.arch);

    // Run the Global Placer.
    PartialPlacement p_placement = run_global_placer(ap_opts,
                                                     atom_nlist,
                                                     ap_netlist,
                                                     prepacker,
                                                     pre_cluster_timing_manager,
                                                     place_delay_model,
                                                     device_ctx);

    // Verify that the partial placement is valid before running the full
    // legalizer.
    const size_t device_width = device_ctx.grid.width();
    const size_t device_height = device_ctx.grid.height();
    VTR_ASSERT(p_placement.verify(ap_netlist,
                                  device_width,
                                  device_height,
                                  device_ctx.grid.get_num_layers()));

    // Generate the pre-cluster timing report now that global placement has
    // updated the timing arc delays to reflect the flat placement.
    pre_cluster_timing_manager.generate_setup_timing_report(atom_nlist,
                                                            g_vpr_ctx.atom().lookup(),
                                                            *device_ctx.arch,
                                                            vpr_setup.AnalysisOpts);

    // Run the Full Legalizer.
    std::unique_ptr<FullLegalizer> full_legalizer = make_full_legalizer(ap_opts.full_legalizer_type,
                                                                        ap_netlist,
                                                                        atom_nlist,
                                                                        prepacker,
                                                                        pre_cluster_timing_manager,
                                                                        ram_mapper,
                                                                        vpr_setup,
                                                                        *device_ctx.arch,
                                                                        device_ctx.grid);
    full_legalizer->legalize(p_placement);

    // Print the number of resources in netlist and number of resources available in architecture
    float target_device_utilization = vpr_setup.PackerOpts.target_device_utilization;
    print_resource_usage();
    // Print the device utilization
    print_device_utilization(target_device_utilization);

    // Write out a flat placement file at the end of Full Legalization if the
    // option is specified.
    if (!vpr_setup.FileNameOpts.write_legalized_flat_place_file.empty()) {
        write_flat_placement(vpr_setup.FileNameOpts.write_legalized_flat_place_file.c_str(),
                             g_vpr_ctx.clustering().clb_nlist,
                             g_vpr_ctx.placement().block_locs(),
                             g_vpr_ctx.clustering().atoms_lookup);
    }

    // Run the Detailed Placer.
    std::unique_ptr<DetailedPlacer> detailed_placer = make_detailed_placer(ap_opts.detailed_placer_type,
                                                                           g_vpr_ctx.placement().blk_loc_registry(),
                                                                           atom_nlist,
                                                                           g_vpr_ctx.clustering().clb_nlist,
                                                                           vpr_setup,
                                                                           *device_ctx.arch);
    detailed_placer->optimize_placement();

    // Clean up some of the global variables that will no longer be used outside
    // of this flow.
    g_vpr_ctx.mutable_placement().clean_placement_context_post_place();
    g_vpr_ctx.mutable_floorplanning().clean_floorplanning_context_post_place();
}

#pragma once
/**
 * @file
 * @author  Alex Singer
 * @date    September 2024
 * @brief   Defines the APNetlist class used to store the connectivity of
 *          primitives in the Analytical Placement context.
 *
 * In the context of Analytical Placement, a block is a collection of atoms
 * (primitives) which want to move together. For example, if one atom in a block
 * should be moved one unit to the left, all atoms in the block want to move one
 * unit to the left.
 *
 * An example of a block is pack molecules, which are atoms which were prepacked
 * together.
 *
 * The nets in the netlist represent the logical connections between AP
 * blocks (inferred from the atom block connectivity), where nets which are
 * unused by Analytical Placement are ignored.
 */

#include <string>
#include <vector>
#include "atom_netlist_fwd.h"
#include "netlist.h"
#include "ap_netlist_fwd.h"
#include "prepack.h"

/**
 * @brief Struct to store fixed block location information
 *
 * Currently assumes that blocks are fixed to single locations (not ranges).
 * TODO: This assumption could be relaxed and allow fixing a range of locations.
 *
 * -1 implies that the block is not fixed in that dimension.
 */
struct APFixedBlockLoc {
    // Value that represents an unfixed dimension.
    static constexpr float UNFIXED_DIM = -1;
    // The dimensions to fix.
    float x = UNFIXED_DIM;
    float y = UNFIXED_DIM;
    int layer_num = UNFIXED_DIM;
    int sub_tile = UNFIXED_DIM;
};

/**
 * @brief The mobility of a block in the APNetlist
 * TODO: It would be nice if the netlist contained lists of moveable and fixed
 *       block ids.
 */
enum class APBlockMobility : bool {
    MOVEABLE, // The block is not constrained in any dimension.
    FIXED     // The block is fixed.
};

/**
 * @brief The netlist used during Analytical Placement
 *
 * This class abstracts the placeable blocks and connections between the blocks
 * away from the atom netlist. An APBlock is assumed to be some collection of
 * primitive blocks and an APNet is assumed to be some connection between the
 * APBlocks. These need not have physical meaning.
 */
class APNetlist : public Netlist<APBlockId, APPortId, APPinId, APNetId> {
  public:
    /**
     * @brief Constructs a netlist
     *
     *  @param name The name of the netlist (e.g. top-level module)
     *  @param id   A unique identifier for the netlist (e.g. a secure digest of
     *              the input file)
     */
    APNetlist(std::string name = "", std::string id = "")
        : Netlist(name, id) {}

    APNetlist(const APNetlist& rhs) = default;
    APNetlist& operator=(const APNetlist& rhs) = default;

  public: // Public Accessors
    /*
     * Blocks
     */

    /// @brief Returns the molecules that this block represents.
    const std::vector<PackMoleculeId>& block_molecules(const APBlockId id) const;

    /// @brief Returns the mobility of this block.
    APBlockMobility block_mobility(const APBlockId id) const;

    /// @brief Returns the location of this block, if the block is fixed.
    ///        This method should not be used if the block is moveable.
    const APFixedBlockLoc& block_loc(const APBlockId id) const;

    /*
     * Pins
     */

    /// @brief Returns the atom pin that corresponds with the given AP pin.
    AtomPinId pin_atom_pin(const APPinId id) const;

    /*
     * Nets
     */

    /// @brief Returns the atom net that corresponds with the given AP net.
    AtomNetId net_atom_net(const APNetId id) const;

  public: // Public Mutators
    /*
     * Note: all create_*() functions will silently return the appropriate ID
     * if it has already been created.
     */

    /**
     * @brief Create or return an existing block in the netlist
     *
     *  @param name      The unique name of the block
     *  @param molecules The molecules this block represents
     */
    APBlockId create_block(const std::string& name, const std::vector<PackMoleculeId>& molecules);

    /**
     * @brief Fixes a block at the given location
     *
     *  @param id  The block to fix
     *  @param loc The location to fix the block to
     */
    void set_block_loc(const APBlockId id, const APFixedBlockLoc& loc);

    /**
     * @brief Create or return an existing port in the netlist
     *
     *  @param blk_id The block the port is associated with
     *  @param name   The name of the port
     *  @param width  The width (number of bits) of the port
     *  @param type   The type of the port (INPUT, OUTPUT, or CLOCK)
     */
    APPortId create_port(const APBlockId blk_id, const std::string& name, BitIndex width, PortType type);

    /**
     * @brief Create or return an existing pin in the netlist
     *
     *  @param port_id  The port this pin is associated with
     *  @param port_bit The bit index of the pin in the port
     *  @param net_id   The net the pin drives/sinks
     *  @param pin_type The type of the pin (driver/sink)
     *  @param atom_pin_id The atom pin that this pin is modeling.
     *  @param is_const Indicates whether the pin holds a constant value (e.g.
     *                  vcc/gnd)
     */
    APPinId create_pin(const APPortId port_id, BitIndex port_bit, const APNetId net_id, const PinType pin_type, const AtomPinId atom_pin_id, bool is_const = false);

    /**
     * @brief Create an empty, or return an existing net in the netlist
     *
     *  @param name The unique name of the net
     *  @param atom_net_id The atom net that this net is modeling.
     */
    APNetId create_net(const std::string& name, const AtomNetId atom_net_id);

  private: // Private Members
    /*
     * Netlist compression / optimization
     */

    /// @brief Removes invalid components and reorders them
    void clean_blocks_impl(const vtr::vector_map<APBlockId, APBlockId>& block_id_map) override;
    void clean_ports_impl(const vtr::vector_map<APPortId, APPortId>& port_id_map) override;
    void clean_pins_impl(const vtr::vector_map<APPinId, APPinId>& pin_id_map) override;
    void clean_nets_impl(const vtr::vector_map<APNetId, APNetId>& net_id_map) override;

    void rebuild_block_refs_impl(const vtr::vector_map<APPinId, APPinId>& pin_id_map, const vtr::vector_map<APPortId, APPortId>& port_id_map) override;
    void rebuild_port_refs_impl(const vtr::vector_map<APBlockId, APBlockId>& block_id_map, const vtr::vector_map<APPinId, APPinId>& pin_id_map) override;
    void rebuild_pin_refs_impl(const vtr::vector_map<APPortId, APPortId>& port_id_map, const vtr::vector_map<APNetId, APNetId>& net_id_map) override;
    void rebuild_net_refs_impl(const vtr::vector_map<APPinId, APPinId>& pin_id_map) override;

    /// @brief Shrinks internal data structures to required size to reduce
    ///        memory consumption
    void shrink_to_fit_impl() override;

    /*
     * Component removal
     */
    void remove_block_impl(const APBlockId blk_id) override;
    void remove_port_impl(const APPortId port_id) override;
    void remove_pin_impl(const APPinId pin_id) override;
    void remove_net_impl(const APNetId net_id) override;

    /*
     * Sanity checks
     */
    // Verify the internal data structure sizes match
    bool validate_block_sizes_impl(size_t num_blocks) const override;
    bool validate_port_sizes_impl(size_t num_ports) const override;
    bool validate_pin_sizes_impl(size_t num_pins) const override;
    bool validate_net_sizes_impl(size_t num_nets) const override;

  private: // Private Data
    /// @brief Molecules of each block
    vtr::vector_map<APBlockId, std::vector<PackMoleculeId>> block_molecules_;
    /// @brief Type of each block
    vtr::vector_map<APBlockId, APBlockMobility> block_mobilities_;
    /// @brief Location of each block (if fixed).
    ///        NOTE: This vector will likely be quite sparse.
    vtr::vector_map<APBlockId, APFixedBlockLoc> block_locs_;
    /// @brief Atom pin associated with each AP pin.
    vtr::vector_map<APPinId, AtomPinId> pin_atom_pin_;
    /// @brief Atom net associated with each AP net.
    vtr::vector_map<APNetId, AtomNetId> net_atom_net_;
};

#pragma once
/**
 * @file
 * @author  Alex Singer
 * @date    September 2024
 * @brief   The declaration of the PartialPlacement object
 *
 * The partial placement object stores the placement of the APNetlist blocks
 * during different stages of the Analytical Placement flow. The Partial
 * Placement need not represent a legal placement; however, the placed blocks
 * will always be on the device and will respect fixed block locations.
 */

#include <cmath>
#include "ap_netlist.h"
#include "physical_types.h"
#include "vtr_vector.h"

/**
 * @brief A partial placement during the Analytical Placement flow
 *
 * The goal of this class is to contain positional information about the blocks
 * that gets passed around during analytical placement.
 *
 * The placement of a given APBlock is given by the following values:
 *  - x_loc         The x-position of the APBlock on the device grid
 *  - y_loc         The y-position of the APBlock on the device grid
 *  - layer_num     The layer on the device grid this block is on
 *  - sub_tile      The sub-tile this APBlock wants to be a part of
 * TODO: Not sure if we want to keep the sub tile, but it may be useful for
 *       transferring information from the PartialLegalizer to the FullLegalizer.
 *
 * x_loc, y_loc, and layer_num are represented by doubles since APBlocks can be
 * placed in continuous space, rather than constrained to the integer device
 * grid of legal locations. These are doubles rather than floats since they
 * better fit the matrix solver we currently use.
 *
 * layer_num is represented by an int since it is not decided by an analytical
 * solver, but rather by the legalizers; so it does not need to be in continuous
 * space.
 *
 * This object assumes that the APNetlist object is static during the operation
 * of Analytical Placement (no blocks are added or removed).
 *
 * Note: The placement information was stored in this object as a struct of
 *       arrays instead of an array of structs since it is assumed that the
 *       main operations being performed on this placement will be analytical;
 *       thus the x positions and y positions will likely be stored and computed
 *       as separate continuous vectors.
 */
struct PartialPlacement {
    /// @brief The x locations of all the APBlocks
    vtr::vector<APBlockId, double> block_x_locs;
    /// @brief The y locations of all the APBlocks
    vtr::vector<APBlockId, double> block_y_locs;
    /// @brief The layers of the device of all the APBlocks
    vtr::vector<APBlockId, double> block_layer_nums;
    /// @brief The sub tiles of all the APBlocks
    vtr::vector<APBlockId, int> block_sub_tiles;

    // Remove the default constructor. Need to construct this using an APNetlist.
    PartialPlacement() = delete;

    /**
     * @brief Construct the partial placement
     *
     * Uses the APNetlist object to allocate space for the locations of all
     * APBlocks.
     *
     *  @param netlist  The APNetlist which contains the blocks to be placed.
     */
    PartialPlacement(const APNetlist& netlist)
        : block_x_locs(netlist.blocks().size(), -1.0)
        , block_y_locs(netlist.blocks().size(), -1.0)
        , block_layer_nums(netlist.blocks().size(), 0.0)
        , block_sub_tiles(netlist.blocks().size(), 0) {
        // Note: All blocks are initialized to:
        //      x_loc = -1.0
        //      y_loc = -1.0
        //      layer_num = 0.0
        //      sub_tile = 0
        // Load the fixed block locations
        for (APBlockId blk_id : netlist.blocks()) {
            if (netlist.block_mobility(blk_id) != APBlockMobility::FIXED)
                continue;
            const APFixedBlockLoc& loc = netlist.block_loc(blk_id);
            if (loc.x != -1)
                block_x_locs[blk_id] = loc.x;
            if (loc.y != -1)
                block_y_locs[blk_id] = loc.y;
            if (loc.layer_num != -1)
                block_layer_nums[blk_id] = loc.layer_num;
            if (loc.sub_tile != -1)
                block_sub_tiles[blk_id] = loc.sub_tile;
        }
    }

    /**
     * @brief Get the location of the physical tile that contains the given
     *        AP block.
     *
     * VTR uses an integer grid. In AP, we consider a tile at (1,1) to be
     * centered at (1.5,1.5). When converting from doubles back to integer
     * tiles, we simply take the floor, so the tile above would receive all
     * points from [(1,1) to (2,2)). When converting fixed blocks from the
     * integral VPR grid to the AP locations, we should therefore add (0.5,0.5)
     * to them so they are centered in their grid tiles (assuming the tiles are
     * 1x1).
     *
     * FIXME: Ideally this should return an ID to the tile, not a location.
     *        This is important since there is a distinction between the two.
     *        We know a block will be at that tile, but it would not be at the
     *        corner of the block (likely it would be at the center).
     */
    inline t_physical_tile_loc get_containing_tile_loc(APBlockId blk_id) const {
        // We take the floor here since we want to know which tile contains this
        // block. On a grid, if the block is located at x=0.99999, it would still
        // be in the first tile. This is because we assume that the blocks will
        // ultimately end up in the center of the tile, not at the top left
        // corner of it. The physical tile loc is just a way of identifying that
        // tile.
        // TODO: This may be a bit more complicated than this. This assumes that
        //       all tiles are 1x1, but it could be the case that this is on
        //       the edge of a much larger block. In reality this should try
        //       to go into the tile where it is closest to the center. What
        //       is written here is not necessarily wrong, but it may put blocks
        //       which on are the edge of large blocks into the large blocks.
        //       However, this may not even matter if the partial legalizer is
        //       doing its job!
        int tile_x_loc = std::floor(block_x_locs[blk_id]);
        int tile_y_loc = std::floor(block_y_locs[blk_id]);
        int tile_layer = std::floor(block_layer_nums[blk_id]);
        return t_physical_tile_loc(tile_x_loc, tile_y_loc, tile_layer);
    }

    /**
     * @brief Computes the HPWL of the current partial placement solution.
     *
     * NOTE: This gets the HPWL of the netlist and partial placement as it
     *       currently appears. The user should be aware that fractional
     *       positions of blocks are not realistic and the netlist is ignoring
     *       some nets to make the analytical placement problem easier.
     *       The user should use an atom or cluster level HPWL for an accurate
     *       result. This is used for the Global Placer.
     */
    double get_hpwl(const APNetlist& netlist) const;

    /**
     * @brief Estimate the wirelength of the current placement assuming that all
     *        blocks will be placed exactly where they are in the partial placement.
     *
     * NOTE: This is an underestimate of the actual wirelength mainly due to
     *       the placement not being legalized yet.
     */
    double estimate_post_placement_wirelength(const APNetlist& netlist) const;

    /**
     * @brief Verify the block_x_locs and block_y_locs vectors
     *
     * Currently ensures:
     *  - All blocks have locs
     *  - All blocks are on the device
     *  - All fixed locs are correct
     *
     *  @param netlist      The APNetlist used to generate this placement
     *  @param grid_width   The width of the device grid
     *  @param grid_height  The height of the device grid
     */
    bool verify_locs(const APNetlist& netlist,
                     size_t grid_width,
                     size_t grid_height) const;

    /**
     * @brief Verify the block_layer_nums vector
     *
     * Currently ensures:
     *  - All blocks have layer_nums
     *  - All blocks are on the device
     *  - All fixed layers are correct
     *
     *  @param netlist          The APNetlist used to generate this placement
     *  @param grid_num_layers  The number of layers in the device grid
     */
    bool verify_layer_nums(const APNetlist& netlist,
                           size_t grid_num_layers) const;

    /**
     * @brief Verify the sub_tiles
     *
     * Currently ensures:
     *  - All sub_tiles are non-negative (implies unset)
     *
     *  @param netlist  The APNetlist used to generate this placement
     */
    bool verify_sub_tiles(const APNetlist& netlist) const;

    /**
     * @brief Verify the entire partial placement object
     *
     * Runs all of the verification checks above.
     *
     *  @param netlist          The APNetlist used to generate this placement
     *  @param grid_width       The width of the device grid
     *  @param grid_height      The height of the device grid
     *  @param grid_num_layers  The number of layers in the device grid
     */
    bool verify(const APNetlist& netlist,
                size_t grid_width,
                size_t grid_height,
                size_t grid_num_layers) const;
};

#pragma once
/**
 * @file
 * @author  Alex Singer
 * @date    October 2024
 * @brief   The declarations of the Global Placer base class which is used to
 *          define the functionality of all global placers in the AP flow.
 *
 * A Global Placer creates a Partial Placement given only the netlist and the
 * architecture. It uses analytical techniques (i.e. efficient numerical
 * minimization of an objective function of a placement) to find a placement
 * that optimizes for objectives subject to some of the constraints of the FPGA
 * architecture.
 */

#include <memory>
#include "ap_flow_enums.h"
#include "flat_placement_density_manager.h"
#include "partial_legalizer.h"

// Forward declarations
class APNetlist;
class AnalyticalSolver;
class LogicalModels;
class PartialLegalizer;
class PlaceDelayModel;
class PreClusterTimingManager;
class Prepacker;
struct PartialPlacement;

/**
 * @brief The Global Placer base class
 *
 * This declares the functionality that all Global Placers will use. This
 * provides a standard interface for the global placers so they can be used
 * interchangeably. This makes it very easy to test and compare different global
 * placers.
 */
class GlobalPlacer {
  public:
    virtual ~GlobalPlacer() {}

    /**
     * @brief Constructor of the base GlobalPlacer class
     *
     *  @param netlist      Netlist of the design at some abstraction level;
     *                      typically this would have some atoms and groups of
     *                      atoms (in a pack pattern).
     *  @param log_verbosity    The verbosity of log messages in the Global
     *                          Placer.
     */
    GlobalPlacer(const APNetlist& ap_netlist, int log_verbosity)
        : ap_netlist_(ap_netlist)
        , log_verbosity_(log_verbosity) {}

    /**
     * @brief Perform global placement on the given netlist.
     *
     * The role of a global placer is to try and find a placement for the given
     * netlist which optimizes some objective function and is mostly legal.
     */
    virtual PartialPlacement place() = 0;

  protected:
    /// @brief The APNetlist the global placer is placing.
    const APNetlist& ap_netlist_;

    /// @brief The setting of how verbose the log messages should be in the
    ///        global placer. Anything larger than zero will display per
    ///        iteration status messages.
    int log_verbosity_;
};

/**
 * @brief A factory method which creates a Global Placer of the given type.
 */
std::unique_ptr<GlobalPlacer> make_global_placer(e_ap_analytical_solver analytical_solver_type,
                                                 e_ap_partial_legalizer partial_legalizer_type,
                                                 const APNetlist& ap_netlist,
                                                 const Prepacker& prepacker,
                                                 const AtomNetlist& atom_netlist,
                                                 const DeviceGrid& device_grid,
                                                 const std::vector<t_logical_block_type>& logical_block_types,
                                                 const std::vector<t_physical_tile_type>& physical_tile_types,
                                                 const LogicalModels& models,
                                                 PreClusterTimingManager& pre_cluster_timing_manager,
                                                 std::shared_ptr<PlaceDelayModel> place_delay_model,
                                                 float ap_timing_tradeoff,
                                                 bool generate_mass_report,
                                                 const std::vector<std::string>& target_density_arg_strs,
                                                 unsigned num_threads,
                                                 int log_verbosity);

/**
 * @brief A Global Placer based on the SimPL work for analytical ASIC placement.
 *          https://doi.org/10.1145/2461256.2461279
 *
 * This placement technique uses a solver to generate a placement that optimizes
 * over some objective function and is likely very illegal (has many overlapping
 * blocks and blocks in the wrong places). This solution represents the "lower-
 * bound" on the solution quality.
 *
 * This technique passes this "lower-bound" solution into a legalizer, which
 * tries to find the closest legal solution to the lower-bound solution (by
 * spreading out blocks and placing them in legal positions). This often
 * destroys the quality of the lower-bound solution, and is considered an
 * "upper-bound" on the solution quality.
 *
 * Each iteration of this global placer, the upper-bound solution is fed into
 * the solver as a "hint" to what a legal solution looks like. This allows the
 * solver to produce another placement which will make decisions knowing where
 * the blocks will end-up in the legal solution. This worstens the quality of
 * the lower-bound solution; however, after passing this solution back into
 * the legalizer, this will likely improve the quality of the upper-bound
 * solution.
 *
 * Over several iterations the upper-bound and lower-bound solutions will
 * approach each other until a good quality, mostly-legal solution is found.
 */
class SimPLGlobalPlacer : public GlobalPlacer {
  private:
    /// @brief The maximum number of iterations the global placer can perform.
    static constexpr size_t max_num_iterations_ = 100;

    /// @brief The target relative gap between the HPWL of the upper-bound and
    ///        lower-bound placements. The placer will stop if the difference
    ///        between the two bounds, normalized to the upper-bound, is smaller
    ///        than this number.
    ///        This number was empircally found to work well.
    static constexpr double target_hpwl_relative_gap_ = 0.01;

    /// @brief The solver which generates the lower-bound placement.
    std::unique_ptr<AnalyticalSolver> solver_;

    /// @brief The density manager the partial legalizer will optimize over.
    std::shared_ptr<FlatPlacementDensityManager> density_manager_;

    /// @brief The legalizer which generates the upper-bound placement.
    std::unique_ptr<PartialLegalizer> partial_legalizer_;

    /// @brief The pre-cluster timing manager which manages how the timing of
    ///        the netlist is computed.
    PreClusterTimingManager& pre_cluster_timing_manager_;

    /// @brief A placement delay model which is used to help compute the delays
    ///        of connections in the AP netlist.
    std::shared_ptr<PlaceDelayModel> place_delay_model_;

  public:
    /**
     * @brief Constructor for the SimPL Global Placer
     *
     * Constructs the solver and partial legalizer.
     */
    SimPLGlobalPlacer(e_ap_analytical_solver analytical_solver_type,
                      e_ap_partial_legalizer partial_legalizer_type,
                      const APNetlist& ap_netlist,
                      const Prepacker& prepacker,
                      const AtomNetlist& atom_netlist,
                      const DeviceGrid& device_grid,
                      const std::vector<t_logical_block_type>& logical_block_types,
                      const std::vector<t_physical_tile_type>& physical_tile_types,
                      const LogicalModels& models,
                      PreClusterTimingManager& pre_cluster_timing_manager,
                      std::shared_ptr<PlaceDelayModel> place_delay_model,
                      float ap_timing_tradeoff,
                      bool generate_mass_report,
                      const std::vector<std::string>& target_density_arg_strs,
                      unsigned num_threads,
                      int log_verbosity);

    /**
     * @brief Run a SimPL-like global placement algorithm
     *
     * This iteratively runs the solver and legalizer until a good quality and
     * mostly-legal placement is found.
     */
    PartialPlacement place() final;
};

#pragma once
/**
 * @file
 * @author  Alex Singer
 * @date    September 2024
 * @brief   Defines the FullLegalizer class which takes a partial AP placement
 *          and generates a fully legal clustering and placement which can be
 *          routed by VTR.
 */

#include <memory>
#include <unordered_set>
#include "ap_flow_enums.h"
#include "cluster_legalizer.h"

// Forward declarations
class APNetlist;
class AtomNetlist;
class ClusteredNetlist;
class DeviceGrid;
struct PartialPlacement;
class PlaceMacros;
class PreClusterTimingManager;
class Prepacker;
class RamMapper;
struct t_arch;
struct t_vpr_setup;

/**
 * @brief The full legalizer in an AP flow
 *
 * Given a valid partial placement (of any level of legality), will produce a
 * fully legal clustering and clustered placement for use in the rest of the
 * VTR flow.
 */
class FullLegalizer {
  public:
    virtual ~FullLegalizer() {}

    FullLegalizer(const APNetlist& ap_netlist,
                  const AtomNetlist& atom_netlist,
                  const Prepacker& prepacker,
                  const PreClusterTimingManager& pre_cluster_timing_manager,
                  const RamMapper& ram_mapper,
                  const t_vpr_setup& vpr_setup,
                  const t_arch& arch,
                  const DeviceGrid& device_grid)
        : ap_netlist_(ap_netlist)
        , atom_netlist_(atom_netlist)
        , prepacker_(prepacker)
        , pre_cluster_timing_manager_(pre_cluster_timing_manager)
        , ram_mapper_(ram_mapper)
        , vpr_setup_(vpr_setup)
        , arch_(arch)
        , device_grid_(device_grid) {}

    /**
     * @brief Perform legalization on the given partial placement solution
     *
     *  @param p_placement  A valid partial placement (passes verify method).
     *                      This implies that all blocks are placed on the
     *                      device grid and fixed blocks are observed.
     */
    virtual void legalize(const PartialPlacement& p_placement) = 0;

    /// @brief Update drawing data structure for current placement
    void update_drawing_data_structures();

  protected:
    /**
     * @brief Recreate the device grid (and RR graph if needed) after final
     *        clustering, when auto device sizing is used.
     *
     * The device grid estimated before packing may differ from the one needed
     * after final clustering. This method finalizes the device size and ensures
     * the RR graph matches it before placement begins.
     */
    void recreate_device_if_needed();

    /// @brief The AP Netlist to fully legalize the flat placement of.
    const APNetlist& ap_netlist_;

    /// @brief The Atom Netlist used to generate the AP Netlist.
    const AtomNetlist& atom_netlist_;

    /// @brief The Prepacker used to create molecules from the Atom Netlist.
    const Prepacker& prepacker_;

    /// @brief Pre-Clustering timing manager, hold pre-computed delay information
    ///        at the primitive level prior to packing.
    const PreClusterTimingManager& pre_cluster_timing_manager_;

    const RamMapper& ram_mapper_;

    /// @brief The VPR setup options passed into the VPR flow. This must be
    ///        mutable since some parts of packing modify the options.
    const t_vpr_setup& vpr_setup_;

    /// @brief Information on the architecture of the FPGA.
    const t_arch& arch_;

    /// @brief The device grid which records where clusters can be placed.
    const DeviceGrid& device_grid_;
};

/**
 * @brief A factory method which creates a Full Legalizer of the given type.
 */
std::unique_ptr<FullLegalizer> make_full_legalizer(e_ap_full_legalizer full_legalizer_type,
                                                   const APNetlist& ap_netlist,
                                                   const AtomNetlist& atom_netlist,
                                                   const Prepacker& prepacker,
                                                   const PreClusterTimingManager& pre_cluster_timing_manager,
                                                   const RamMapper& ram_mapper,
                                                   const t_vpr_setup& vpr_setup,
                                                   const t_arch& arch,
                                                   const DeviceGrid& device_grid);

/**
 * @brief FlatRecon: The Flat Placement Reconstruction Full Legalizer.
 *
 * Reconstructs (packs and places) an input flat placement with minimal
 * disturbance. The flat placement may be read from a ``.fplace`` file or
 * taken from Global Placement (GP). In both cases the input is expected to be
 * near-legal.
 *
 * Before packing, molecules are sorted so that long carry chain molecules are
 * priorizited. For molecules in the same priority group, the number of external pins
 * is used as a tie-breaker. It then groups the molecules according to the tiles
 * determined from their flat placement.
 *
 * The packing consists of three passes:
 * 1) Self clustering: For each tile, form as few clusters as possible from
 *    molecules targeting that tile, and does not create more clusters than the
 *    tile can accommodate. Try clustering with the faster SKIP_INTRA_LB_ROUTE
 *    legality strategy (after each molecule is added) first; if the resulting
 *    cluster turns out to be unroutable, packing it is retried with the FULL
 *    legality checking strategy. Molecules that still cannot be clustered
 *    (incompatible with the tile or with the newly formed clusters) are passed
 *    to the neighbor pass.
 *
 * 2) Neighbor clustering: For each unclustered molecule, inspect clusters in
 *    the 8 neighboring tiles within the same layer. Tiles are processed in
 *    ascending order of average molecules-per-cluster. The unclustered molecule is
 *    added to an existing cluster if compatible (and all 8 are checked); no new
 *    clusters are created in this pass.
 *
 * 3) Orphan-window clustering: Remaining “orphan” molecules are clustered by
 *    repeated BFS expansions centered at seeds chosen by highest external input
 *    pin count. From each seed’s assigned location, try to cluster orphan molecules
 *    within a Manhattan distance ≤ radius. The default radius is 8 (empirically
 *    minimizes cluster count without inflating displacement on Titan benchmarks).
 *    If the resulting clusters do not fit the device, the pass is retried with
 *    radius 16, and finally with a radius spanning the whole device. Larger radii
 *    reduce cluster count but can increase displacement.
 *
 * After cluster creation, each cluster is placed by the initial placer at the
 * grid location nearest to the centroid of its atoms.
 */
class FlatRecon : public FullLegalizer {
  public:
    using FullLegalizer::FullLegalizer;

    /**
     * @brief Perform the FlatRecon full legalization.
     */
    void legalize(const PartialPlacement& p_placement) final;

  private:
    /// @brief Mapping from subtile location to legalization cluster id to keep
    ///        track of clusters created.
    /// TODO: It might make sense to store this as a 3D NDMatrix of arrays where we can
    ///       index into the [layer][x][y][subtile] and get the cluster ID at that location.
    ///       It will be faster than using an unordered map and likely more space efficient.
    std::unordered_map<t_pl_loc, LegalizationClusterId> loc_to_cluster_id_placed;

    /// @brief Mapping from a molecule id to its desired physical tile location.
    vtr::vector<PackMoleculeId, t_physical_tile_loc> mol_desired_physical_tile_loc;

    /// @brief Mapping from legalization cluster ids to subtile locations. Using
    ///        unordered_map instead of vtr::vector since LegalizationClusterIds
    ///        can have significant gaps as you create a new ID for each cluster
    ///        you attempt to create.
    std::unordered_map<LegalizationClusterId, t_pl_loc> cluster_locs;

    /// @brief 3D NDMatrix of legalization cluster ids. Stores the cluster ids at
    ///        that tile location and can be accessed in the format of [layer][x][y].
    ///        This is stored to be used in the neighbor pass.
    vtr::NdMatrix<std::unordered_set<LegalizationClusterId>, 3> tile_clusters_matrix;

    /**
     * @brief Helper method to sort and group molecules by desired tile location.
     *        It first sorts by being in a long carry chain, then by external input
     *        pin count.
     * @return Mapping from tile location to sorted vector of molecules that
     *         want to be in that tile.
     */
    std::unordered_map<t_physical_tile_loc, std::vector<PackMoleculeId>>
    sort_and_group_blocks_by_tile(const PartialPlacement& p_placement);

    /**
     * @brief Helper method to create clusters at a given tile location using
     *        given vector of molecules.
     *
     * Iterates over each subtile in the same order each time, hence trying to
     * create the fewest clusters in that tile. It also checks the compatibility
     * of the molecules with the tile before creating a cluster. Stores the cluster
     * ids' to check their legality or clean afterwards if needed.
     *
     *  @param tile_loc                        The physical tile location that clusters aimed to be created.
     *  @param tile_type                       The physical type of the tile that clusters aimed to be created.
     *  @param tile_molecules                  A vector of molecule ids aimed to be placed in that tile.
     *  @param cluster_legalizer               The cluster legalizer which is used to create and grow clusters.
     *  @param primitive_candidate_block_types A list of candidate block types for the given molecule to create a cluster.
     *  @return The set of LegalizationClusterIds created in that tile.
     */
    std::unordered_set<LegalizationClusterId>
    cluster_molecules_in_tile(const t_physical_tile_loc& tile_loc,
                              const t_physical_tile_type_ptr& tile_type,
                              const std::vector<PackMoleculeId>& tile_molecules,
                              ClusterLegalizer& cluster_legalizer,
                              const vtr::vector<LogicalModelId, std::vector<t_logical_block_type_ptr>>& primitive_candidate_block_types);

    /**
     * @brief Helper method to perform self clustering pass.
     *
     * Iterates over each tile and first tries to create the fewest clusters
     * in that tile with SKIP_INTRA_LB_ROUTE strategy. If the resulting
     * cluster is found to be unroutable when fully checked, retry adding the
     * molecules with the FULL strategy before going to next tile.
     *
     *  @param cluster_legalizer               The cluster legalizer which is used to create and grow clusters. The result of
     *                                         this pass is an updated cluster_legalizer.
     *  @param device_grid                     The device grid used to get physical tile types.
     *  @param primitive_candidate_block_types A list of candidate block types for the given molecule to create a cluster.
     *  @param tile_blocks                     The list of molecules to pack in each non-empty tile.
     */
    void self_clustering(ClusterLegalizer& cluster_legalizer,
                         const DeviceGrid& device_grid,
                         const vtr::vector<LogicalModelId, std::vector<t_logical_block_type_ptr>>& primitive_candidate_block_types,
                         std::unordered_map<t_physical_tile_loc, std::vector<PackMoleculeId>>& tile_blocks);

    /**
     * @brief Helper method to perform neighbor clustering.
     *
     * For each unclustered molecule, examines clusters in the 8 neighboring tiles.
     * Neighbor tiles are processed in order of increasing average molecule density.
     * The molecule is then added to an existing cluster if compatible. No new
     * clusters are created in this pass.
     *
     *  @return The set of molecule ids clustered in that pass.
     */
    std::unordered_set<PackMoleculeId>
    neighbor_clustering(ClusterLegalizer& cluster_legalizer,
                        const vtr::vector<LogicalModelId, std::vector<t_logical_block_type_ptr>>& primitive_candidate_block_types);

    /**
     * @brief Helper method to perform orphan window clustering.
     *
     * Iteratively selects a seed orphan molecule (highest external input pins).
     * From the seed’s assigned location, expands within the given Manhattan
     * search radius in a BFS manner to find nearby orphan molecules. Compatible
     * neighbors are added to the seed’s cluster in order of proximity. After
     * reaching the search radius, the process repeats with new seeds until all
     * orphan molecules are clustered.
     *
     *  @param cluster_legalizer               The cluster legalizer which is used to create and grow clusters.
     *  @param primitive_candidate_block_types A list of candidate block types for the given molecule to create a cluster.
     *  @param search_radius                   The search radius that determines the allowed max distance from the seed
     *                                         molecule to candidate molecules.
     *  @return The set of LegalizationClusterIds created in that pass.
     */
    std::unordered_set<LegalizationClusterId>
    orphan_window_clustering(ClusterLegalizer& cluster_legalizer,
                             const vtr::vector<LogicalModelId, std::vector<t_logical_block_type_ptr>>& primitive_candidate_block_types,
                             int search_radius);
    /**
     * @brief Helper method to report the clustering summary.
     */
    void report_clustering_summary(ClusterLegalizer& cluster_legalizer,
                                   std::unordered_set<PackMoleculeId>& neighbor_pass_molecules,
                                   std::unordered_set<LegalizationClusterId>& orphan_window_clusters);

    /**
     * @brief Helper method to create clusters with self, neighbor, and orphan window clustering.
     *
     *  @param cluster_legalizer The cluster legalizer which is used to create and grow clusters. Keeps track of
     *                           the clusters created and molecules clustered while checking cluster legality.
     *  @param p_placement       The partial placement used to guide where each molecule should be placed.
     */
    void create_clusters(ClusterLegalizer& cluster_legalizer,
                         const PartialPlacement& p_placement);

    /**
     * @brief Helper method to perform initial placement on clusters created.
     *
     * Each cluster is placed by the initial placer at the grid location nearest
     * to the centroid of its atoms.
     */
    void place_clusters(const PartialPlacement& p_placement);
};

/**
 * @brief The Naive Full Legalizer.
 *
 * This Full Legalizer will try to create clusters exactly where they want to
 * according to the Partial Placement. It will grow clusters from atoms that
 * are placed in the same tile, then it will try to place the cluster at that
 * location. If a location cannot be found, once all other clusters have tried
 * to be placed, it will try to find anywhere the cluster will fit and place it
 * there.
 */
class NaiveFullLegalizer : public FullLegalizer {
  public:
    using FullLegalizer::FullLegalizer;

    /**
     * @brief Perform naive full legalization.
     */
    void legalize(const PartialPlacement& p_placement) final;

  private:
    /**
     * @brief Helper method to create the clusters from the given partial
     *        placement.
     * TODO: Should return a ClusteredNetlist object, but need to wait until
     *       it is separated from load_cluster_constraints.
     */
    void create_clusters(const PartialPlacement& p_placement);

    /**
     * @brief Helper method to place the clusters based on the given partial
     *        placement.
     */
    void place_clusters(const ClusteredNetlist& clb_nlist,
                        const PlaceMacros& place_macros,
                        const PartialPlacement& p_placement);
};

/**
 * @brief APPack: A flat-placement-informed Packer Placer.
 *
 * The idea of APPack is to use the flat-placement information generated by the
 * AP Flow to guide the Packer and Placer to a better solution.
 *
 * In the Packer, the flat-placement can provide more context for the clusters
 * to pull in atoms that want to be near the other atoms in the cluster, and
 * repel atoms that are far apart. This can potentially make better clusters
 * than a Packer that does not know that information.
 *
 * In the Placer, the flat-placement can help decide where clusters of atoms
 * want to be placed. If this placement is then fed into a Simulated Annealing
 * based Detailed Placement step, this would enable it to converge on a better
 * answer faster.
 */
class APPack : public FullLegalizer {
  public:
    using FullLegalizer::FullLegalizer;

    /**
     * @brief Run APPack.
     *
     * This will call the Packer and Placer using the options provided by the
     * user for these stages in VPR.
     */
    void legalize(const PartialPlacement& p_placement) final;
};

#pragma once
/**
 * @file
 * @author  Alex Singer
 * @date    February 2025
 * @brief   Defines the DetailedPlacer class which takes a fully legal clustering
 *          and placement and optimizes them while remaining legal.
 */

#include <memory>
#include "ap_flow_enums.h"
#include "clustered_netlist_utils.h"
#include "placer.h"
#include "vpr_utils.h"

/**
 * @brief The detailed placer in an AP flow.
 *
 * Given a fully legal clustering and clustered placement, will optimize the
 * solution while remaining fully legal (able to be used in the rest of the VPR
 * flow).
 */
class DetailedPlacer {
  public:
    virtual ~DetailedPlacer() {}

    DetailedPlacer() = default;

    /**
     * @brief Optimize the current legal placement.
     */
    virtual void optimize_placement() = 0;
};

/**
 * @brief A factory method which creates a Detailed Placer of the given type.
 */
std::unique_ptr<DetailedPlacer> make_detailed_placer(e_ap_detailed_placer detailed_placer_type,
                                                     const BlkLocRegistry& curr_clustered_placement,
                                                     const AtomNetlist& atom_netlist,
                                                     const ClusteredNetlist& clustered_netlist,
                                                     t_vpr_setup& vpr_setup,
                                                     const t_arch& arch);

/**
 * @brief The Identity Detailed Placer.
 *
 * This detailed placer does literally nothing to the legal placement. This
 * class is used as a placeholder to make the higher-level code easier to work
 * with.
 */
class IdentityDetailedPlacer : public DetailedPlacer {
  public:
    using DetailedPlacer::DetailedPlacer;

    void optimize_placement() final {}
};

/**
 * @brief The Annealer Detailed Placer.
 *
 * This Detailed Placer passes the legal solution into the Annealer in the
 * VPR flow (uses the legal solution as the initial placement). This performs
 * the Simulated Annealing algorithm on the solution at the cluster level to
 * try and find a better clustered placement.
 *
 * This Detailed Placer reuses the options from the Placer stage of VPR for this
 * stage. So options passed to the Placer will be used in here.
 */
class AnnealerDetailedPlacer : public DetailedPlacer {
  public:
    /**
     * @brief Construct the Annealer Detailed Placer class.
     *
     *  @param curr_clustered_placement
     *      The legalized placement solution to pass as the initial placement
     *      into the annealer.
     *  @param atom_netlist
     *      The netlist of atoms in the circuit.
     *  @param clustered_netlist
     *      The netlist of clusters created by the Full Legalizer.
     *  @param vpr_setup
     *      The setup variables, used to get the params from the user.
     *  @param arch
     *      The FPGA architecture to optimize onto.
     */
    AnnealerDetailedPlacer(const BlkLocRegistry& curr_clustered_placement,
                           const AtomNetlist& atom_netlist,
                           const ClusteredNetlist& clustered_netlist,
                           t_vpr_setup& vpr_setup,
                           const t_arch& arch);

    /**
     * @brief Run the annealer.
     */
    void optimize_placement() final;

  private:
    /// @brief The placer class, which contains the annealer.
    std::unique_ptr<Placer> placer_;

    /// @brief A lookup between the block pin indices and pb graph pins.
    IntraLbPbPinLookup pb_gpin_lookup_;

    /// @brief A lookup between CLB pins and atom pins.
    ClusteredPinAtomPinsLookup netlist_pin_lookup_;
};

