379	PartialPlacement SimPLGlobalPlacer::place() {
380	    // Create a timer to time the entire global placement time.
381	    vtr::ScopedStartFinishTimer global_placer_time("AP Global Placer");
382	    // Create a timer to keep track of how long the solver and legalizer take.
383	    vtr::Timer runtime_timer;
384	    // Print the status header.
385	    if (log_verbosity_ >= 1)
386	        print_SimPL_status_header();
387	    // Initialize the partial placement object.
388	    PartialPlacement p_placement(ap_netlist_);
389	
390	    float total_time_spent_in_solver = 0.0f;
391	    float total_time_spent_in_legalizer = 0.0f;
392	    float total_time_spent_updating_timing = 0.0f;
393	
394	    // Create a partial placement object to store the best placement found during
395	    // global placement. It is possible for the global placement to hit a minimum
396	    // in the middle of its iterations, this lets us keep that solution.
397	    PartialPlacement best_p_placement(ap_netlist_);
398	    double best_ub_hpwl = std::numeric_limits<double>::max();
399	
400	    // Initialize graphics for analytical placement, setting the reference in
401	    // the draw state.
402	    APDrawManager draw_manager(p_placement);
403	
404	    // Pause to show initial FPGA state before any solving begins.
405	    draw_manager.pause("Analytical Placement: Starting Global Placement");
406	
407	    // Run the global placer.
408	    for (size_t i = 0; i < max_num_iterations_; i++) {
409	        float iter_start_time = runtime_timer.elapsed_sec();
410	
411	        // Run the solver.
412	        float solver_start_time = runtime_timer.elapsed_sec();
413	        solver_->solve(i, p_placement);
414	        float solver_end_time = runtime_timer.elapsed_sec();
415	        double lb_hpwl = p_placement.get_hpwl(ap_netlist_);
416	
417	        // Update graphics after analytical solver
418	        draw_manager.update_graphics(i, APDrawType::Solver);
419	
420	        // Run the legalizer.
421	        float legalizer_start_time = runtime_timer.elapsed_sec();
422	        partial_legalizer_->legalize(p_placement);
423	        float legalizer_end_time = runtime_timer.elapsed_sec();
424	        double ub_hpwl = p_placement.get_hpwl(ap_netlist_);
425	
426	        // Update graphics after legalizer
427	        draw_manager.update_graphics(i, APDrawType::Legalizer);
428	
429	        // Perform a timing update
430	        float timing_update_start_time = runtime_timer.elapsed_sec();
431	        update_timing_info_with_gp_placement(pre_cluster_timing_manager_,
432	                                             *place_delay_model_.get(),
433	                                             p_placement,
434	                                             ap_netlist_);
435	        solver_->update_net_weights(pre_cluster_timing_manager_);
436	        float timing_update_end_time = runtime_timer.elapsed_sec();
437	
438	        total_time_spent_in_solver += solver_end_time - solver_start_time;
439	        total_time_spent_in_legalizer += legalizer_end_time - legalizer_start_time;
440	        total_time_spent_updating_timing += timing_update_end_time - timing_update_start_time;
441	
442	        // Print some stats
443	        if (log_verbosity_ >= 1) {
444	            float cpd_ns = -1.0f;
445	            float stns_ns = -1.0f;
446	            if (pre_cluster_timing_manager_.is_valid()) {
447	                cpd_ns = pre_cluster_timing_manager_.get_timing_info().least_slack_critical_path().delay() * 1e9;
448	                stns_ns = pre_cluster_timing_manager_.get_timing_info().setup_total_negative_slack() * 1e9;
449	            }
450	
451	            float iter_end_time = runtime_timer.elapsed_sec();
452	            print_SimPL_status(i, lb_hpwl, ub_hpwl,
453	                               cpd_ns,
454	                               stns_ns,
455	                               solver_end_time - solver_start_time,
456	                               legalizer_end_time - legalizer_start_time,
457	                               timing_update_end_time - timing_update_start_time,
458	                               iter_end_time - iter_start_time);
459	        }
460	
461	        // If this placement is better than the best we have seen, save it.
462	        // TODO: This is not correct for timing. We want to use a costing
463	        //       function that takes timing into account as well. We do not just
464	        //       want the lowest HPWL.
465	        if (ub_hpwl < best_ub_hpwl) {
466	            best_ub_hpwl = ub_hpwl;
467	            best_p_placement = p_placement;
468	        }
469	
470	        // Exit condition: If the upper-bound and lower-bound HPWLs are
471	        // sufficiently close together then stop.
472	        double hpwl_gap = ub_hpwl - lb_hpwl;
473	        double hpwl_relative_gap;
474	        if (ub_hpwl != 0.0)
475	            hpwl_relative_gap = hpwl_gap / ub_hpwl;
476	        else if (lb_hpwl != 0.0)
477	            hpwl_relative_gap = hpwl_gap / lb_hpwl;
478	        else
479	            hpwl_relative_gap = 0.0;
480	
481	        if (hpwl_relative_gap < target_hpwl_relative_gap_)
482	            break;
483	    }
484	
485	    // Update the setup slacks. This is performed down here (as well as being
486	    // inside the GP loop) since the best_p_placement may not be the p_placement
487	    // from the last iteration of GP.
488	    update_timing_info_with_gp_placement(pre_cluster_timing_manager_,
489	                                         *place_delay_model_.get(),
490	                                         best_p_placement,
491	                                         ap_netlist_);
492	
493	    // Print statistics on the solver used.
494	    solver_->print_statistics();
495	
496	    // Print statistics on the partial legalizer used.
497	    partial_legalizer_->print_statistics();
498	
499	    VTR_LOG("Global Placer Statistics:\n");
500	    VTR_LOG("\tTime spent in solver: %g seconds\n", total_time_spent_in_solver);
501	    VTR_LOG("\tTime spent in legalizer: %g seconds\n", total_time_spent_in_legalizer);
502	    VTR_LOG("\tTime spent updating timing: %g seconds\n", total_time_spent_updating_timing);
503	
504	    // Pause to show the final global placement result before handing off.
505	    draw_manager.pause("Analytical Placement: Global Placement Complete");
506	
507	    // Print some statistics on the final placement.
508	    VTR_LOG("Placement after Global Placement:\n");
509	    print_placement_stats(best_p_placement,
510	                          ap_netlist_,
511	                          *density_manager_,
512	                          pre_cluster_timing_manager_);
513	
514	    // Return the placement from the final iteration.
515	    return best_p_placement;
516	}
